static int em_check_patient_injection(const char *val) {
    if (val == NULL || val[0] == '\0')
        return 0;
    /* Detect SQL injection patterns */
    if (strstr(val, "' OR ") != NULL) return 1;
    if (strstr(val, "1=1") != NULL) return 1;
    if (strstr(val, "-- ") != NULL) return 1;
    /* Detect XSS patterns */
    if (strstr(val, "<script") != NULL) return 1;
    if (strstr(val, "alert(") != NULL) return 1;
    /* Detect path traversal */
    if (strstr(val, "../") != NULL) return 1;
    /* Detect format string */
    if (strstr(val, "%s") != NULL) return 1;
    if (strstr(val, "%n") != NULL) return 1;
    /* Detect JNDI injection */
    if (strstr(val, "${jndi") != NULL) return 1;
    return 0;
}
